// ---- Text composable ----
@Composable
fun TextExamples() {
    Column(
        modifier = Modifier.padding(16.dp)
    ) {
        // Basic text
        Text(text = "Hello, Kotlin-chan!")

        // Text with style
        Text(
            text = "Styled Text",
            fontSize = 24.sp,
            fontWeight = FontWeight.Bold,
            color = Color.Blue
        )

        // Text with modifier
        Text(
            text = "Text with background",
            modifier = Modifier
                .background(Color.LightGray)
                .padding(8.dp)
        )

        // Multi-line text
        Text(
            text = "This is a very long text that will wrap to multiple lines if it exceeds the available width.",
            maxLines = 2,
            overflow = TextOverflow.Ellipsis
        )

        // Text with click
        Text(
            text = "Click me!",
            modifier = Modifier.clickable { 
                println("Text clicked!")
            }
        )
    }
}

// ---- Image composable ----
@Composable
fun ImageExamples() {
    Column(
        modifier = Modifier.padding(16.dp)
    ) {
        // Image from resources
        Image(
            painter = painterResource(id = R.drawable.ic_launcher),
            contentDescription = "App icon",
            modifier = Modifier.size(64.dp)
        )

        // Image with content scale
        Image(
            painter = painterResource(id = R.drawable.banner),
            contentDescription = "Banner",
            contentScale = ContentScale.Crop,
            modifier = Modifier
                .fillMaxWidth()
                .height(200.dp)
        )

        // Image with click
        Image(
            painter = painterResource(id = R.drawable.avatar),
            contentDescription = "Avatar",
            modifier = Modifier
                .size(100.dp)
                .clip(CircleShape)
                .clickable { 
                    println("Avatar clicked!")
                }
        )

        // Image from URL (using Coil)
        AsyncImage(
            model = "https://example.com/image.jpg",
            contentDescription = "Network image",
            modifier = Modifier.size(150.dp)
        )
    }
}

// ---- Button composable ----
@Composable
fun ButtonExamples() {
    Column(
        modifier = Modifier.padding(16.dp),
        verticalArrangement = Arrangement.spacedBy(8.dp)
    ) {
        // Basic button
        Button(
            onClick = { println("Button clicked!") }
        ) {
            Text(text = "Click me")
        }

        // Button with icon
        Button(
            onClick = { println("Icon button clicked!") }
        ) {
            Icon(
                imageVector = Icons.Default.Favorite,
                contentDescription = "Favorite"
            )
            Spacer(modifier = Modifier.width(8.dp))
            Text(text = "Like")
        }

        // Button with different colors
        Button(
            onClick = { println("Primary button") },
            colors = ButtonDefaults.buttonColors(
                containerColor = MaterialTheme.colorScheme.primary,
                contentColor = Color.White
            )
        ) {
            Text(text = "Primary")
        }

        // Outlined button
        OutlinedButton(
            onClick = { println("Outlined button") }
        ) {
            Text(text = "Outlined")
        }

        // Text button
        TextButton(
            onClick = { println("Text button") }
        ) {
            Text(text = "Text Button")
        }

        // Icon button
        IconButton(
            onClick = { println("Icon button") }
        ) {
            Icon(
                imageVector = Icons.Default.Settings,
                contentDescription = "Settings"
            )
        }

        // Disabled button
        Button(
            onClick = { /* Won't work */ },
            enabled = false
        ) {
            Text(text = "Disabled")
        }
    }
}

// ---- Combined example ----
@Composable
fun UserProfile() {
    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp),
        horizontalAlignment = Alignment.CenterHorizontally
    ) {
        // Avatar
        Image(
            painter = painterResource(id = R.drawable.avatar),
            contentDescription = "User avatar",
            modifier = Modifier
                .size(100.dp)
                .clip(CircleShape)
        )

        Spacer(modifier = Modifier.height(16.dp))

        // Name
        Text(
            text = "Kotlin-chan",
            fontSize = 24.sp,
            fontWeight = FontWeight.Bold
        )

        Spacer(modifier = Modifier.height(8.dp))

        // Bio
        Text(
            text = "Android developer & Compose enthusiast",
            fontSize = 16.sp,
            color = Color.Gray
        )

        Spacer(modifier = Modifier.height(16.dp))

        // Follow button
        Button(
            onClick = { println("Follow clicked!") },
            modifier = Modifier.fillMaxWidth()
        ) {
            Text(text = "Follow")
        }
    }
}

